queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?stringers a :Stringers .
    ?stringers p:name ?name .
    ?stringers p:Payment ?payment_f .
    FILTER((STR(?payment_f) = "2000" || STR(?payment_f) = "2000.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?editors a :Editors .
    ?editors p:name ?name .
    ?editors p:Payment ?payment_f .
    FILTER((STR(?payment_f) = "2000" || STR(?payment_f) = "2000.0"))
    BIND(?name AS ?o0)
  }
}

